def prompt(msg, default=None, secret=False):
    try:
        if default:
            value = input(f"{msg} [{default}]: ")
            return value if value else default
        return input(f"{msg}: ")
    except EOFError:
        return default or ""


def validate_table_name(name):
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", name or ""):
        raise ValueError("Invalid table name.")
    return name


def validate_columns(columns):
    if not columns:
        return None
    parts = [c.strip() for c in columns.split(",") if c.strip()]
    for col in parts:
        if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", col):
            raise ValueError(f"Invalid column name: {col}")
    return parts


def normalize_file_path(file_path):
    p = Path(file_path).expanduser().resolve()
    if not p.is_file():
        raise FileNotFoundError(f"File not found: {p}")
    return str(p)


def escape_mysql_string(value):
    return value.replace("\\", "\\\\").replace("'", "\\'")


def build_load_data_sql(
    file_path,
    table_name,
    columns=None,
    field_terminated_by=",",
    enclosed_by='"',
    escaped_by="\\",
    line_terminated_by="\\n",
    ignore_lines=1,
):
    escaped_path = escape_mysql_string(file_path)
    sql = (
        "LOAD DATA LOCAL INFILE '{}' "
        "INTO TABLE `{}` "
        "CHARACTER SET utf8mb4 "
        "FIELDS TERMINATED BY '{}' "
        "OPTIONALLY ENCLOSED BY '{}' "
        "ESCAPED BY '{}' "
        "LINES TERMINATED BY '{}' "
    ).format(
        escaped_path,
        table_name,
        escape_mysql_string(field_terminated_by),
        escape_mysql_string(enclosed_by),
        escape_mysql_string(escaped_by),
        escape_mysql_string(line_terminated_by),
    )

    if ignore_lines and int(ignore_lines) > 0:
        sql += "IGNORE {} LINES ".format(int(ignore_lines))

    if columns:
        sql += "({})".format(", ".join(f"`{c}`" for c in columns))

    return sql


def main():
    host = prompt("MySQL host", "127.0.0.1")
